mapper.select:
SELECT id, name, type, price, stock, version, deleted, created_at, updated_at
FROM products
WHERE deleted = #{deleted}

    AND type = #{type}

ORDER BY created_at DESC

mapper.update:
UPDATE products
name = #{product.name}, type = #{product.type}, price = #{product.price}, updated_at = #{product.updatedAt}
WHERE id = #{id, typeHandler=org.shining319.newsstand_backend_system.config.UuidBinaryTypeHandler} AND deleted = false

UPDATE products
SET stock = #{newStock},
    version = version + 1,
    updated_at = #{updatedAt}
WHERE id = #{id, typeHandler=org.shining319.newsstand_backend_system.config.UuidBinaryTypeHandler}
AND deleted = false
AND version = #{version}
